mapper.select:
/** CmmtAuthorityDao.select */
select

from
	cmmt_authority a
where
	authority_id = #{authorityId}

/** CmmtAuthorityDao.selectByName */
select

from
	cmmt_authority a
where
	authority_nm = #{authorityNm}

mapper.insert:
/** CmmtAuthorityDao.insert */
insert into cmmt_authority (
	authority_id
	,authority_nm
	,purpose
	,creator_id
	,created_dt
	,updater_id
	,updated_dt
) values (
	#{authorityId}
	,#{authorityNm}
	,#{purpose}
	,#{creatorId}
	,#{createdDt}
	,#{updaterId}
	,#{updatedDt}
)

mapper.update:
/** CmmtAuthorityDao.update */
update cmmt_authority set
	authority_nm = #{authorityNm}
	,purpose = #{purpose}
	,creator_id  = #{creatorId}
	,created_dt  = #{createdDt}
	,updater_id  = #{updaterId}
	,updated_dt  = #{updatedDt}
where
	authority_id = #{authorityId}

mapper.delete:
/** CmmtAuthorityDao.delete */
delete from
	cmmt_authority
where
	authority_id = #{authorityId}
